const resp = $input.first().json;
const messages = Array.isArray(resp.messages) ? resp.messages.slice() : [];

// Sort chronologically (ascending by ts). Channel history arrives newest-first, thread replies arrive oldest-first; sorting normalises both.
messages.sort((a, b) => parseFloat(a.ts || '0') - parseFloat(b.ts || '0'));

const parseEvent = $('Parse Event').first().json;

const contextLines = messages
  .filter(m => m.text && m.text.trim())
  .map(m => `<${m.user || m.bot_id || 'bot'}>: ${m.text}`)
  .join('\n');

return [{
  json: {
    question: parseEvent.question,
    channel: parseEvent.channel,
    ts: parseEvent.ts,
    thread_ts: parseEvent.thread_ts,
    user: parseEvent.user,
    context: contextLines || '(no prior context in this channel or thread)',
    thread_parent_ts: parseEvent.thread_ts || parseEvent.ts
  }
}];

const buildCtx = $input.first().json;
const context = buildCtx.context || '';

// Extract unique Slack user IDs referenced in the context (matches <UXXXX> / <WXXXX>).
const ids = new Set();
for (const m of context.matchAll(/<([UW][A-Z0-9]+)>/g)) {
  ids.add(m[1]);
}

// No user mentions in context, pass straight through.
if (ids.size === 0) {
  return [{ json: buildCtx }];
}

// Fetch each user in parallel via users.info. Continue on individual failure so one bad ID doesn't drop the whole run.
const lookups = await Promise.all(
  Array.from(ids).map(async id => {
    try {
      const resp = await this.helpers.httpRequestWithAuthentication.call(
        this,
        'slackApi',
        { method: 'GET', url: 'https://slack.com/api/users.info', qs: { user: id }, json: true }
      );
      return { id, ok: resp && resp.ok, user: resp && resp.user };
    } catch (err) {
      return { id, ok: false, error: String(err) };
    }
  })
);

// Build userId -> display name map (prefer display_name, fall back to real_name, then username, then ID).
const userMap = {};
for (const r of lookups) {
  if (!r.ok || !r.user) continue;
  const p = r.user.profile || {};
  userMap[r.id] = p.display_name || p.real_name || r.user.real_name || r.user.name || r.id;
}

// Rewrite context: replace <USERID> occurrences with @DisplayName. Leave unresolved IDs in raw form.
const newContext = context.replace(/<([UW][A-Z0-9]+)>/g, (match, id) => userMap[id] ? `@${userMap[id]}` : match);

return [{ json: { ...buildCtx, context: newContext } }];

